import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { View, Text, TouchableOpacity, StyleSheet, FlatList, Alert, AppState } from 'react-native';

const generateToken = () => {
  const ts = Date.now().toString(36);
  const rand = Math.random().toString(36).slice(2, 12);
  return `lt_${ts}_${rand}`;
};

const createTokenRecord = (reason = 'offline') => ({
  id: generateToken(),
  reason,
  createdAt: Date.now(),
});

export default function OfflineTokenGenerator() {
  const [isOnline, setIsOnline] = useState(true);
  const [tokens, setTokens] = useState([]);
  const appState = useRef(AppState.currentState);

  const currentStatusLabel = useMemo(() => (isOnline ? 'Online' : 'Offline'), [isOnline]);

  const addToken = useCallback((reason) => {
    const token = createTokenRecord(reason);
    setTokens((prev) => [token, ...prev]);
    return token;
  }, []);

  const handleOfflineAction = useCallback(() => {
    if (!isOnline) {
      const token = addToken('temporary_session');
      Alert.alert('Offline Token Generated', token.id);
    } else {
      Alert.alert('Online', 'No temporary token needed while online.');
    }
  }, [addToken, isOnline]);

  useEffect(() => {
    const interval = setInterval(() => {
      const simulatedConnectivity = Math.random() > 0.25;
      setIsOnline(simulatedConnectivity);
      if (!simulatedConnectivity) {
        addToken('connectivity_loss');
      }
    }, 8000);

    return () => clearInterval(interval);
  }, [addToken]);

  useEffect(() => {
    const subscription = AppState.addEventListener('change', (nextAppState) => {
      if (appState.current.match(/active/) && nextAppState.match(/inactive|background/)) {
        if (!isOnline) addToken('app_background_offline');
      }
      appState.current = nextAppState;
    });

    return () => subscription.remove();
  }, [addToken, isOnline]);

  const renderItem = ({ item }) => (
    <View style={styles.tokenCard}>
      <Text style={styles.tokenText}>{item.id}</Text>
      <Text style={styles.metaText}>Reason: {item.reason}</Text>
      <Text style={styles.metaText}>Created: {new Date(item.createdAt).toLocaleString()}</Text>
    </View>
  );

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Offline Session Token Generator</Text>
      <View style={[styles.statusPill, isOnline ? styles.online : styles.offline]}>
        <Text style={styles.statusText}>{currentStatusLabel}</Text>
      </View>

      <TouchableOpacity style={styles.button} onPress={handleOfflineAction}>
        <Text style={styles.buttonText}>Generate Local Session Token</Text>
      </TouchableOpacity>

      <TouchableOpacity
        style={[styles.button, styles.secondaryButton]}
        onPress={() => setIsOnline((v) => !v)}
      >
        <Text style={styles.buttonText}>Toggle Connectivity</Text>
      </TouchableOpacity>

      <Text style={styles.sectionTitle}>Generated Tokens</Text>
      <FlatList
        data={tokens}
        keyExtractor={(item) => item.id}
        renderItem={renderItem}
        ListEmptyComponent={<Text style={styles.emptyText}>No tokens generated yet.</Text>}
        contentContainerStyle={tokens.length === 0 ? styles.emptyContainer : undefined}
      />
    </View>
  );
}

